script:
frappe.ui.form.on('Job Applicant', {
	refresh(frm) {
		if (frm.is_new() || !frm.doc.resume_attachment) {
			return;
		}

		const label = frm.doc.is_ocr_processed ? __('Re-process CV with OCR') : __('Process CV with OCR');

		frm.add_custom_button(label, () => {
			frappe.call({
				method: 'wa_hr_api.recruitment.process_cv_with_ocr',
				args: { applicant: frm.doc.name },
				freeze: true,
				freeze_message: __('Processing CV with OCR...'),
				callback: () => {
					frm.reload_doc();
				},
			});
		}, __('Actions'));

		if (frm.doc.is_ocr_processed) {
			frm.add_custom_button(__('View OCR Data'), () => {
				frappe.set_route('Form', 'Job Applicant', frm.doc.name);
				frm.scroll_to_field('ocr_section');
			}, __('Actions'));
		}
	},
});
